import boto3
from botocore.exceptions import ClientError

def subscribe_to_sns(topic_arn):
    try:
        sns = boto3.client('sns')
        user_input = input("Enter the URL to subscribe: ")
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_input
        )
        print(f"Subscription created with ARN: {response['SubscriptionArn']}")
    except ClientError as e:
        if e.response['Error']['Code'] == 'InvalidParameter':
            print("Invalid input. Please enter a valid URL.")
        else:
            print(f"An error occurred: {e}")

if __name__ == "__main__":
    topic_arn = "your_sns_topic_arn"
    subscribe_to_sns(topic_arn)